import{_ as a,c as s,o as i,ae as t}from"./chunks/framework.Cd-3tpCq.js";const u=JSON.parse('{"title":"Erreurs rencontrées","description":"","frontmatter":{},"headers":[],"relativePath":"00-cheat-sheet/error.md","filePath":"00-cheat-sheet/error.md"}'),n={name:"00-cheat-sheet/error.md"};function l(r,e,o,p,h,d){return i(),s("div",null,e[0]||(e[0]=[t(`<h1 id="erreurs-rencontrees" tabindex="-1">Erreurs rencontrées <a class="header-anchor" href="#erreurs-rencontrees" aria-label="Permalink to &quot;Erreurs rencontrées&quot;">​</a></h1><h2 id="phpstorm" tabindex="-1">PHPStorm <a class="header-anchor" href="#phpstorm" aria-label="Permalink to &quot;PHPStorm&quot;">​</a></h2><h3 id="entitytypemanager-must-not-be-accessed-before-initialization" tabindex="-1">$entityTypeManager must not be accessed before initialization <a class="header-anchor" href="#entitytypemanager-must-not-be-accessed-before-initialization" aria-label="Permalink to &quot;$entityTypeManager must not be accessed before initialization&quot;">​</a></h3><h4 id="context" tabindex="-1">context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;context&quot;">​</a></h4><p>J&#39;ai créé un formulaire dans lequel j&#39;ai un champ radio qui appelle de l&#39;ajax. la première valeur est sélectionnée par défaut. Si je sélectionne la seconde valeur, l&#39;ajax est appelé correctement. Si ensuite je sélectionne la première valeur, j&#39;ai l&#39;erreur.</p><h4 id="explication" tabindex="-1">Explication <a class="header-anchor" href="#explication" aria-label="Permalink to &quot;Explication&quot;">​</a></h4><p>La classe qui gère mon formulaire à des dépendances qui ne sont pas correctement instanciée lors de l&#39;appel ajax.</p><h4 id="solution" tabindex="-1">Solution <a class="header-anchor" href="#solution" aria-label="Permalink to &quot;Solution&quot;">​</a></h4><p>Drupal propose un trait qui permet de gérer ce genre de problème. Il suffit d&#39;ajouter à l&#39;intérieur de la classe le trait <code>Drupal\\Core\\DependencyInjection\\DependencySerializationTrait</code> :</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> DependencySerializationTrait</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h3 id="git-is-not-installed-cannot-identify-version-of-git-executable-no-response" tabindex="-1">Git is not installed: Cannot identify version of git executable: no response <a class="header-anchor" href="#git-is-not-installed-cannot-identify-version-of-git-executable-no-response" aria-label="Permalink to &quot;Git is not installed: Cannot identify version of git executable: no response&quot;">​</a></h3><p>file -&gt; Invalidate caches... -&gt; Invalidate and restart</p><h3 id="configurer-git-ssh-dans-le-terminal-de-phpstorm" tabindex="-1">Configurer Git ssh dans le terminal de PHPStorm <a class="header-anchor" href="#configurer-git-ssh-dans-le-terminal-de-phpstorm" aria-label="Permalink to &quot;Configurer Git ssh dans le terminal de PHPStorm&quot;">​</a></h3><p>Générer une clef ssh:</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh-keygen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ed25519</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -C</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;maclef@gitlab&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_ed25519_maclef</span></span></code></pre></div><p>Vérifier le remote dans le repo local :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remote</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre></div><p>L&#39;url doit correspondre à celle du ssh.</p><p>Si non (remplacer URL par l&#39;url du repo) :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remote</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set-url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> originer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> URL</span></span></code></pre></div><p>Modifier le fichier .ssh/config :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host gitlab-project</span></span>
<span class="line"><span>  HostName gitlab.com</span></span>
<span class="line"><span>  User git</span></span>
<span class="line"><span>  IdentityFile ~/.ssh/id_ed25519_maclef</span></span>
<span class="line"><span>  AddKeysToAgent yes</span></span></code></pre></div><p>Tester la connexion :</p><div class="language-ssh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ssh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ssh -T git@gitlab-project</span></span></code></pre></div><p>Renvois :</p><div class="language-ssh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ssh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Welcome to GitLab, @user</span></span></code></pre></div>`,26)]))}const g=a(n,[["render",l]]);export{u as __pageData,g as default};
